#!/usr/bin/perl

use strict;
use warnings;

use CGI;
use Storable qw(nstore retrieve);
use Fcntl qw(:flock); # For file locking

# --- Configuration ---
my $SESSION_DIR = "/tmp";
my $SESSION_COOKIE_NAME = "PERL_SESSION_ID";
my $SESSION_EXPIRATION_SECONDS = 3600; # 1 hour
my $SESSION_ID_LENGTH = 32; # Length of the session ID

# --- Global CGI object ---
my $q = CGI->new;

# --- Session Management Functions ---

sub _generate_session_id {
    my @chars = ('a'..'z', 'A'..'Z', '0'..'9');
    my $id = join '', map { $chars[rand @chars] } 1..$SESSION_ID_LENGTH;
    return $id;
}

sub _get_session_file_path {
    my ($session_id) = @_;
    return "$SESSION_DIR/sess_$session_id";
}

sub _lock_session_file {
    my ($fh, $lock_type) = @_;
    flock($fh, $lock_type) or die "Cannot lock session file: $!";
}

sub _unlock_session_file {
    my ($fh) = @_;
    flock($fh, F_UNLCK) or die "Cannot unlock session file: $!";
}

sub _cleanup_expired_sessions {
    # This is a basic cleanup. For high-traffic sites, consider a cron job.
    opendir(my $dh, $SESSION_DIR) or return;
    while (my $file = readdir($dh)) {
        next unless $file =~ /^sess_([a-zA-Z0-9]{$SESSION_ID_LENGTH})$/;
