                unlink $path;
            }
        }
    }
    closedir($dh);
}

sub start_session {
    my $session_id = $q->cookie($SESSION_COOKIE_NAME);
    my %session_data = ();
    my $session_file_path;
    my $fh;

    # Try to load existing session
    if ($session_id) {
        $session_file_path = _get_session_file_path($session_id);
        if (-e $session_file_path) {
            # Open for read and write, create if not exists (though it should exist here)
            # Use +< to preserve content if it exists, for locking
