                    close $fh;
                    unlink $session_file_path; # Remove corrupted file
                    $session_id = undef; # Force new session
                } else {
                    _unlock_session_file($fh);
                    close $fh;
                    # Update modification time to extend session
                    utime time, time, $session_file_path;
                }
            } else {
                warn "Could not open session file $session_file_path for reading: $!";
                $session_id = undef; # Force new session
            }
        } else {
            $session_id = undef; # File not found, treat as new session
        }
    }

    # If no valid session found, create a new one
