sub save_session {
    my ($session_id, $session_data_ref) = @_;
    my $session_file_path = _get_session_file_path($session_id);

    # Update last access time
    $session_data_ref->{_last_access} = time;

    # Open file for writing, create if not exists, truncate if exists
    # Use > to truncate, then flock for exclusive lock.
    # If the file might not exist, use +> or create it first.
    # For Storable, nstore can take a filename, which simplifies things.
    # However, for explicit locking, we need a filehandle.
    my $fh;
    if (open($fh, "+>", $session_file_path)) { # Open for read/write, create/truncate
        _lock_session_file($fh, F_EXLOCK); # Exclusive lock for writing
        eval {
            nstore($session_data_ref, $fh);
        };
        if ($@) {
            warn "Failed to store session data for $session_id: $@";
        }
        _unlock_session_file($fh);
        close $fh;
    } else {
        warn "Could not open session file $session_file_path for writing: $!";
    }
